WITH right_fg0 AS (SELECT * FROM (SELECT "hopsworks_tl_spine"."hopsworks_tl_payload_0" AS "pk", "hopsworks_tl_spine"."hopsworks_tl_payload_1" AS "ts", "hopsworks_tl_spine"."hopsworks_tl_payload_2" AS "is_fraud", "hopsworks_tl_spine"."hopsworks_tl_payload_3" AS "join_pk_pk", "hopsworks_tl_spine"."hopsworks_tl_payload_4" AS "join_evt_ts", "hopsworks_tl_agg"."hopsworks_tl_out_0" AS "amount_min", "hopsworks_tl_agg"."hopsworks_tl_out_1" AS "amount_max", "hopsworks_tl_agg"."hopsworks_tl_out_2" AS "amount_avg" FROM (SELECT "hopsworks_tl_e_0", "hopsworks_tl_seq", MIN(CASE WHEN "hopsworks_tl_marker" = 1 THEN "hopsworks_tl_f_0" WHEN "hopsworks_tl_marker" = 2 THEN "hopsworks_tl_b_0" ELSE NULL END) AS "hopsworks_tl_out_0", MAX(CASE WHEN "hopsworks_tl_marker" = 1 THEN "hopsworks_tl_f_1" WHEN "hopsworks_tl_marker" = 2 THEN "hopsworks_tl_b_1" ELSE NULL END) AS "hopsworks_tl_out_1", CASE WHEN COALESCE(MAX(CASE WHEN "hopsworks_tl_marker" = 1 THEN "hopsworks_tl_cc_0" ELSE NULL END), 0) > 0 THEN CAST(MAX(CASE WHEN "hopsworks_tl_marker" = 1 THEN "hopsworks_tl_cs_0" ELSE NULL END) / MAX(CASE WHEN "hopsworks_tl_marker" = 1 THEN "hopsworks_tl_cc_0" ELSE NULL END) AS DOUBLE) ELSE NULL END AS "hopsworks_tl_out_2" FROM (SELECT "hopsworks_tl_e_0", "hopsworks_tl_marker", "hopsworks_tl_seq", SUM("hopsworks_tl_dc_0") OVER (PARTITION BY "hopsworks_tl_e_0" ORDER BY "hopsworks_tl_ord" RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS "hopsworks_tl_cc_0", SUM("hopsworks_tl_ds_0") OVER (PARTITION BY "hopsworks_tl_e_0" ORDER BY "hopsworks_tl_ord" RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS "hopsworks_tl_cs_0", MIN("hopsworks_tl_v_0") OVER (PARTITION BY "hopsworks_tl_e_0", "hopsworks_tl_bkt" ORDER BY "hopsworks_tl_ord" RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS "hopsworks_tl_f_0", MIN("hopsworks_tl_v_0") OVER (PARTITION BY "hopsworks_tl_e_0", "hopsworks_tl_bkt" ORDER BY "hopsworks_tl_ord" DESC RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS "hopsworks_tl_b_0", MAX("hopsworks_tl_v_1") OVER (PARTITION BY "hopsworks_tl_e_0", "hopsworks_tl_bkt" ORDER BY "hopsworks_tl_ord" RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS "hopsworks_tl_f_1", MAX("hopsworks_tl_v_1") OVER (PARTITION BY "hopsworks_tl_e_0", "hopsworks_tl_bkt" ORDER BY "hopsworks_tl_ord" DESC RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS "hopsworks_tl_b_1" FROM (SELECT "fg1"."pk" AS "hopsworks_tl_e_0", EPOCH_US("fg1"."ts") + CASE WHEN "hopsworks_tl_sgn" = 1 THEN 0 ELSE 3600000001 END AS "hopsworks_tl_ord", 0 AS "hopsworks_tl_marker", NULL AS "hopsworks_tl_seq", CAST(FLOOR((EPOCH_US("fg1"."ts") + CASE WHEN "hopsworks_tl_sgn" = 1 THEN 0 ELSE 3600000001 END) / 3600000000) AS BIGINT) AS "hopsworks_tl_bkt", CASE WHEN "hopsworks_tl_sgn" = 1 THEN "fg1"."amount" ELSE NULL END AS "hopsworks_tl_v_0", CASE WHEN "hopsworks_tl_sgn" = 1 THEN "fg1"."amount" ELSE NULL END AS "hopsworks_tl_v_1", CASE WHEN "fg1"."amount" IS NOT NULL THEN "hopsworks_tl_sgn" ELSE NULL END AS "hopsworks_tl_dc_0", CASE WHEN "hopsworks_tl_sgn" = 1 THEN "fg1"."amount" ELSE - "fg1"."amount" END AS "hopsworks_tl_ds_0" FROM "fs1"."fg1_1" AS "fg1" INNER JOIN (SELECT "fg0"."pk" AS "hopsworks_tl_be_0", MIN(EPOCH_US("fg0"."ts")) - 3600000000 AS "hopsworks_tl_blo", MAX(EPOCH_US("fg0"."ts")) AS "hopsworks_tl_bhi" FROM "fs1"."labels_1" AS "fg0" GROUP BY "fg0"."pk") AS hopsworks_tl_bounds ON "fg1"."pk" = "hopsworks_tl_be_0" CROSS JOIN (SELECT 1 AS "hopsworks_tl_sgn" UNION ALL SELECT -1 AS "hopsworks_tl_sgn") AS hopsworks_tl_sign WHERE EPOCH_US("fg1"."ts") >= "hopsworks_tl_blo" AND EPOCH_US("fg1"."ts") <= "hopsworks_tl_bhi" UNION ALL SELECT "hopsworks_tl_e_0", CASE WHEN "hopsworks_tl_role" = 1 THEN "hopsworks_tl_ord" ELSE "hopsworks_tl_ord" - 3600000000 END AS "hopsworks_tl_ord", "hopsworks_tl_role" AS "hopsworks_tl_marker", "hopsworks_tl_seq", CAST(FLOOR(CASE WHEN "hopsworks_tl_role" = 1 THEN "hopsworks_tl_ord" ELSE "hopsworks_tl_ord" - 3600000000 END / 3600000000) AS BIGINT) AS "hopsworks_tl_bkt", NULL AS "hopsworks_tl_v_0", NULL AS "hopsworks_tl_v_1", NULL AS "hopsworks_tl_dc_0", NULL AS "hopsworks_tl_ds_0" FROM (SELECT "fg0"."pk" AS "hopsworks_tl_e_0", EPOCH_US("fg0"."ts") AS "hopsworks_tl_ord", ROW_NUMBER() OVER (PARTITION BY "fg0"."pk" ORDER BY EPOCH_US("fg0"."ts")) AS "hopsworks_tl_seq", "fg0"."pk" AS "hopsworks_tl_payload_0", "fg0"."ts" AS "hopsworks_tl_payload_1", "fg0"."is_fraud" AS "hopsworks_tl_payload_2", "fg0"."pk" AS "hopsworks_tl_payload_3", "fg0"."ts" AS "hopsworks_tl_payload_4" FROM "fs1"."labels_1" AS "fg0") AS hopsworks_tl_spine CROSS JOIN (SELECT 1 AS "hopsworks_tl_role" UNION ALL SELECT 2 AS "hopsworks_tl_role") AS hopsworks_tl_roles) AS hopsworks_tl) AS hopsworks_tl_win WHERE "hopsworks_tl_marker" >= 1 GROUP BY "hopsworks_tl_e_0", "hopsworks_tl_seq") AS hopsworks_tl_agg INNER JOIN (SELECT "fg0"."pk" AS "hopsworks_tl_e_0", EPOCH_US("fg0"."ts") AS "hopsworks_tl_ord", ROW_NUMBER() OVER (PARTITION BY "fg0"."pk" ORDER BY EPOCH_US("fg0"."ts")) AS "hopsworks_tl_seq", "fg0"."pk" AS "hopsworks_tl_payload_0", "fg0"."ts" AS "hopsworks_tl_payload_1", "fg0"."is_fraud" AS "hopsworks_tl_payload_2", "fg0"."pk" AS "hopsworks_tl_payload_3", "fg0"."ts" AS "hopsworks_tl_payload_4" FROM "fs1"."labels_1" AS "fg0") AS hopsworks_tl_spine ON "hopsworks_tl_agg"."hopsworks_tl_seq" = "hopsworks_tl_spine"."hopsworks_tl_seq" AND ("hopsworks_tl_agg"."hopsworks_tl_e_0" = "hopsworks_tl_spine"."hopsworks_tl_e_0" OR "hopsworks_tl_agg"."hopsworks_tl_e_0" IS NULL AND "hopsworks_tl_spine"."hopsworks_tl_e_0" IS NULL)) AS NA) (SELECT "right_fg0"."pk" AS "pk", "right_fg0"."ts" AS "ts", "right_fg0"."is_fraud" AS "is_fraud", "right_fg0"."amount_min" AS "amount_min", "right_fg0"."amount_max" AS "amount_max", "right_fg0"."amount_avg" AS "amount_avg" FROM right_fg0)
